#include <stdio.h>
#include <stdlib.h>

// Structure to represent a min heap
typedef struct {
   int *arr;
   int size;
   int capacity;
} MinHeap;

// Function to create a min heap
MinHeap* createMinHeap(int capacity) {
   MinHeap* minHeap = (MinHeap*) malloc(sizeof(MinHeap));
   minHeap->arr = (int*) malloc(sizeof(int) * capacity);
   minHeap->size = 0;
   minHeap->capacity = capacity;
   return minHeap;
}

// Function to swap two elements
void swap(int* a, int* b) {
   int temp = *a;
   *a = *b;
   *b = temp;
}

// Function to heapify the min heap
void heapify(MinHeap* minHeap, int index) {
   int smallest = index;
   int left = 2 * index + 1;
   int right = 2 * index + 2;

   if (left < minHeap->size && minHeap->arr[left] < minHeap->arr[smallest])
      smallest = left;

   if (right < minHeap->size && minHeap->arr[right] < minHeap->arr[smallest])
      smallest = right;

   if (smallest != index) {
      swap(&minHeap->arr[index], &minHeap->arr[smallest]);
      heapify(minHeap, smallest);
   }
}

// Function to insert an element into the min heap
void insert(MinHeap* minHeap, int key) {
   if (minHeap->size == minHeap->capacity) {
      printf("Min Heap is full\n");
      return;
   }

   minHeap->arr[minHeap->size] = key;
   int index = minHeap->size;
   minHeap->size++;

   while (index != 0 && minHeap->arr[(index - 1) / 2] > minHeap->arr[index]) {
      swap(&minHeap->arr[index], &minHeap->arr[(index - 1) / 2]);
      index = (index - 1) / 2;
   }
}

// Function to extract the minimum element from the min heap
int extractMin(MinHeap* minHeap) {
   if (minHeap->size == 0)
      return -1;

   if (minHeap->size == 1) {
      int min = minHeap->arr[0];
      minHeap->size--;
      return min;
   }

   int min = minHeap->arr[0];
   minHeap->arr[0] = minHeap->arr[minHeap->size - 1];
   minHeap->size--;
   heapify(minHeap, 0);
   return min;
}

int main() {
   MinHeap* minHeap = createMinHeap(10);
   insert(minHeap, 10);
   insert(minHeap, 20);
   insert(minHeap, 5);
   insert(minHeap, 15);
   insert(minHeap, 30);
   insert(minHeap, 25);

   printf("Extracted Min: %d\n", extractMin(minHeap));
   return 0;
}

